var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"카란티시르 경. 사라졌던 당신이 왜 여기에 계신 겁니까?","JPN":"カランティシル卿。消えたはずのあなたがどうしてここにいるのですか？","ENG":"Sir Carantisir... Why are you here, after all this time?","TWN":"卡蘭堤西爾。消失的你為何會在這裡？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제게 이런 싸움을 걸어오신 이유를 모르겠습니다!","JPN":"私にこうやって戦闘を挑んできた理由がわかりません！","ENG":"Why are you even picking a fight with me?!","TWN":"我不明白你為什麼要向我發起這樣的戰鬥！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"불손한 발언에도 정도가 있는 법이다, 애송이.","JPN":"無礼にも程がある、小娘。","ENG":"Even insolence has its limits, kid.","TWN":"大言不慚也要有個度，小丫頭。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈과 나 사이에 싸움이 성립된다 생각하는가?","JPN":"貴様と俺の間に、戦いが成立すると思うか？","ENG":"You think this is a fight? That you and I are equals?","TWN":"你認為我們之間的戰鬥會成立嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"크윽…!!","JPN":"くっ……！！","ENG":"Kgh...!","TWN":"咳呃……！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_SLASH_BIG_02"},{"id":"L12_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"전임 기사단장의 혈육이기에 조금은 기대했건만 결국 이 정도인가.","JPN":"前騎士団長の血筋ゆえ少しは期待していたのだが、結局この程度か。","ENG":"I expected more from the blood of a former captain, but I suppose this is your limit.","TWN":"雖然是前任騎士團長的血脈，稍微有些期待，但最終也不過如此。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"한심하군. 적어도 네놈 오빠는 실력만큼은 진짜였거늘.","JPN":"不甲斐ない。少なくとも貴様の兄は、実力だけは本物だった。","ENG":"Pathetic. At least your brother had real skill.","TWN":"真是可悲。至少你哥哥的實力是真的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"단장이나 부단장이 이런 꼴이니. 다른 녀석들은 볼 필요도 없겠어.","JPN":"団長も副団長もこの様だ。他のやつらは見るまでもない。","ENG":"If this is what the Captain and Deputy amount to, there's no need to bother with the rest.","TWN":"團長和副團長都這樣，其他傢伙就不用看了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부단장이라면… 피오네 경?","JPN":"副団長というと……フィオネ卿？","ENG":"Deputy...? You mean Dame Fione?","TWN":"副團長的話…菲奧尼卿？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그녀에게 무슨 짓을 한 겁니까!","JPN":"彼女に何をしたのですか！","ENG":"What did you do to her?!","TWN":"你對她做了什麼！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"주제 파악을 할 수 있도록 뼈를 부수고 살을 짓이겼다.","JPN":"身の程がわかるよう、骨を砕き肉を潰してやった。","ENG":"I broke her bones and crushed her flesh, so she'd learn her place.","TWN":"為了讓你認清現實，我打碎了她的骨頭，撕裂了她的肌肉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"무구를 휘두를 땐 몰랐지만, 땅을 기어다니는 모습을 보니 퍽 전갈답더군.","JPN":"武具を振り回しているときにはわからなかったが、地を這う姿を見るとサソリらしかったな。","ENG":"Didn't realize it when she swung that Armament. But seeing her crawl on the ground, she really was a scorpion.","TWN":"揮舞武具時沒注意，但看到她在地上爬行的樣子，確實像蠍子。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금… 레드시프트가 같은 기사단을 습격했다는 겁니까?","JPN":"今……レッドシフトが同じ騎士団を襲撃したと言ったのですか？","ENG":"Are you saying... Red Shift attacked one of its own?!","TWN":"現在……紅移襲擊了同一個騎士團嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"하. 같은 기사라고?","JPN":"は、同じ騎士だと？","ENG":"Hah. One of its own?","TWN":"哈。說是同樣的騎士？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"웃기지도 않는군. 기사단이란 오랜 전통을 맹목적으로 답습할 뿐인 어리석은 집단이다.","JPN":"戯言にもほどがある。騎士団とは長い伝統を盲目的に踏襲しているだけの愚かな集団だ。","ENG":"Don't make me laugh. The Order is nothing but a pack of fools blindly clinging to outdated traditions.","TWN":"真是可笑。所謂的騎士團不過是盲目地沿襲古老傳統的愚蠢組織罷了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그리고 별빛을 나누어 쫓은 결과가 네놈들이 직시한 현실이라면…….","JPN":"そして星の光を分け、追求していた結果が貴様らが直面した現実なら……","ENG":"And if chasing scattered starlight brought you to this pathetic reality...","TWN":"如果你們所面對的現實是追逐星光的結果……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"누군가는 그 틀을 깨어, 선조들의 어리석은 과오를 바로잡아야겠지.","JPN":"誰かはその型を壊し、先祖の愚かな過ちを立て直さなければならない。","ENG":"Then someone needs to break the mold and correct our forebears' mistakes.","TWN":"總得有人打破這個框架，糾正祖先們愚蠢的過錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"그래. 계승식을 통한 무구의 개방으로 말이야.","JPN":"そう。継承式を通じた武具の開放でな。","ENG":"And that starts by unleashing the Armaments through proper succession.","TWN":"是的。通過繼承儀式來解放武具。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"커억… 쿨럭, 허억……!","JPN":"ガハッ……ゲホッ、はあっ……！","ENG":"Ack... *Cough!* *Gasp...!*","TWN":"咳呃……咳咳，嚇呃……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BOMB_DAMAGE_DOWN"},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신이… 그걸 어떻게……?","JPN":"あなたが……それをどうやって……？","ENG":"You... How could you possibly know about that...?","TWN":"你……怎麼會知道……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"한심한 녀석. 별의 기억을 읽은 이가 네놈뿐이라고 생각한 거냐?","JPN":"情けないやつめ。星の記憶を読んだ者が貴様だけだと思っていたのか？","ENG":"Fool. You thought you were the only one who read the memories of the stars?","TWN":"真是個可悲的傢伙。你以為只有你一個人讀過星星的記憶嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"앞서 부린 객기의 결과가 고작 이것에 그친다면 더는 얘기할 가치도 없겠지.","JPN":"先日の無謀の結果がこの程度なら、もう話す価値もないだろう。","ENG":"If your little stunt amounted to this, there's no point talking further.","TWN":"如果之前的逞強只導致這樣的結果，那就沒有繼續談論的價值了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"작별이다, 애송이.","JPN":"さらばだ、小娘。","ENG":"Goodbye, kid.","TWN":"告別了，小鬼。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"……예전에 했던 이야기는 취소해야겠군.","JPN":"……この前した話はなかったことにしないとな。","ENG":"...Looks like I'll have to take back what I said before.","TWN":"……之前說過的話要收回了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"레드시프트가 자네를 단장으로 인정하기에는, 아직 시간이 필요한 모양이야.","JPN":"レッドシフトが君を団長として認めるには、まだ時間が必要のようだ。","ENG":"Red Shift seems to need more time to accept you as their captain...","TWN":"紅移要認可你做團長，看來還需要一些時間啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"익숙한 그림자가 자신의 몸을 가려, 있을 리 없는 남성의 존재를 시사함에.","JPN":"見慣れた人影が自分の体を隠し、いるはずのない男性の存在を示していることに。","ENG":"A familiar shadow blocked the body, hinting at a man who couldn't possibly be here.","TWN":"熟悉的暗影遮住了自己的身體，暗示著不可能存在的男性。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"일순, 시간이 멈춘듯한 감각이 들었다.","JPN":"一瞬、時間が止まったような感覚がした。","ENG":"For a moment, time seemed to stop.","TWN":"一瞬間，感覺時間彷彿停止了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"어, 째서…….","JPN":"どう、して……","ENG":"W-why...?","TWN":"呃，切開……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"친우가 서로의 고민을 덜어주는 건 흔한 일이 아닌가.","JPN":"親友とは互いの悩みも分け合うものだろう。","ENG":"It's not unusual for friends to share one another's burdens.","TWN":"好友之間互相幫助不是很平常嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"자네가 아직 악몽에서 벗어나지 않았다면, 그곳에서 벗어나게 하는 건 나의 몫이겠지.","JPN":"君がまだ悪夢から目覚めずにいるのなら、目を覚ませてやるのが私の役割だ。","ENG":"And if you're still trapped in a nightmare, then I'll be the one to pull you out.","TWN":"如果你還沒有從惡夢中解脫出來，那就由我來帶你離開那裡吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"일어서라, 에스테로사.","JPN":"立て、エステロサ。","ENG":"Get up, Esterosa.","TWN":"站起來，艾斯特洛索。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"네가 했던 맹세를 기억하고, 의무로부터 맞서는 거다.","JPN":"君の誓いを思い出し、義務に立ち向かうのだ。","ENG":"Remember the vow you made, and face duty.","TWN":"回憶你的誓言，勇敢面對你的義務。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};